def load_risk_scorer(artifacts: RealModelArtifacts | None = None) -> RiskScorer:
    artifact_config = artifacts or artifacts_from_environment()
    validation = validate_real_model_artifacts(artifact_config)
    if not validation.available:
        return MockRiskScorer(scorer_mode="real_unavailable", unavailable_reason=validation.reason)

    try:
        model = _load_local_joblib_artifact(artifact_config.model_path, artifact_config.artifact_root)
        return RealCatBoostRiskScorer(
            model=model,
            feature_order=validation.feature_order or [],
            model_version=validation.model_version or REAL_MODEL_VERSION_FALLBACK,
        )
    except Exception as exc:
        reason = f"real model failed to load: {exc}"
        return MockRiskScorer(scorer_mode="real_unavailable", unavailable_reason=reason)


def artifacts_from_environment() -> RealModelArtifacts:
    return RealModelArtifacts(
        model_path=Path(os.environ.get("REHEALTH_CVD_MODEL_PATH", DEFAULT_MODEL_PATH)),
        feature_order_path=Path(os.environ.get("REHEALTH_CVD_FEATURE_ORDER_PATH", DEFAULT_FEATURE_ORDER_PATH)),
        metadata_path=Path(os.environ.get("REHEALTH_CVD_MODEL_META_PATH", DEFAULT_MODEL_META_PATH)),
        artifact_root=Path(os.environ.get("REHEALTH_CVD_ARTIFACT_ROOT", LOCAL_ARTIFACT_ROOT)),
    )


def validate_real_model_artifacts(artifacts: RealModelArtifacts) -> ArtifactValidationResult:
    try:
        model_path = _resolve_local_artifact_path(artifacts.model_path, artifacts.artifact_root)
        feature_order_path = _resolve_local_artifact_path(artifacts.feature_order_path, artifacts.artifact_root)
        metadata_path = _resolve_local_artifact_path(artifacts.metadata_path, artifacts.artifact_root)
    except ModelUnavailableError as exc:
        return ArtifactValidationResult(available=False, reason=str(exc))

    if not model_path.exists():
        return ArtifactValidationResult(available=False, reason=f"model artifact missing: {artifacts.model_path}")
    if not feature_order_path.exists():
        return ArtifactValidationResult(available=False, reason=f"feature order artifact missing: {artifacts.feature_order_path}")

    try:
        feature_order = _load_feature_order(feature_order_path)
        if feature_order != FEATURE_FIELDS:
            return ArtifactValidationResult(
                available=False,
                reason="feature order mismatch; real scorer requires Android C1 CVD 16 order",
                feature_order=feature_order,
            )
        model_version = _load_model_version(metadata_path)
        return ArtifactValidationResult(
            available=True,
            reason=None,
            feature_order=feature_order,
            model_version=model_version,
        )
    except Exception as exc:
        return ArtifactValidationResult(available=False, reason=f"artifact validation failed: {exc}")


def _load_feature_order(path: Path) -> list[str]:
    if path.suffix.lower() == ".json":
        data = json.loads(path.read_text(encoding="utf-8"))
        if isinstance(data, list):
            return [str(item) for item in data]
        if isinstance(data, dict) and isinstance(data.get("feature_cols"), list):
            return [str(item) for item in data["feature_cols"]]
        raise ValueError("JSON feature order must be a list or contain feature_cols")

    loaded = joblib.load(path)
    if not isinstance(loaded, list):
        raise ValueError("feature order artifact must contain a list")
    return [str(item) for item in loaded]


def _load_model_version(path: Path) -> str:
    if not path.exists():
        return REAL_MODEL_VERSION_FALLBACK
    data = json.loads(path.read_text(encoding="utf-8"))
    version = data.get("model_version")
    if not isinstance(version, str) or not version:
        return REAL_MODEL_VERSION_FALLBACK
    return version


def _load_local_joblib_artifact(path: Path, artifact_root: Path) -> Any:
    resolved_path = _resolve_local_artifact_path(path, artifact_root)
    return joblib.load(resolved_path)


def _resolve_local_artifact_path(path: Path, artifact_root: Path) -> Path:
    root = artifact_root.resolve()
    candidate = path if path.is_absolute() else Path.cwd() / path
    resolved = candidate.resolve()
    if root != resolved and root not in resolved.parents:
        raise ModelUnavailableError(f"artifact path must stay under local artifact root {artifact_root}: {path}")
    return resolved

